const { DateTime } = require('luxon');
const body = $input.item.json.body;
const event = body.events[0];

const userId = event.source.userId;
const replyToken = event.replyToken;
const eventType = event.type;
const msgType = event.message?.type || 'postback';
const msgText = event.message?.text || '';
const postbackData = event.postback?.data || '';
const msgId = event.message?.id || '';

// Timezone Logic (Asia/Taipei)
const now = DateTime.now().setZone('Asia/Taipei');
// Work Day Threshold: 6 AM (If before 6AM, count as previous day)
const workDate = now.hour < 6 ? now.minus({ days: 1 }) : now;
const workDay = workDate.toFormat('yyyy/MM/dd');

return {
  json: {
    userId,
    replyToken,
    eventType,
    msgType,
    msgText,
    postbackData,
    msgId,
    workDay,
    timestamp: now.toMillis()
  }
};

const d = $('擷取訊息資訊').item.json;
const flexContents = {
  type: 'bubble',
  body: {
    type: 'box',
    layout: 'vertical',
    contents: [
      { type: 'text', text: '👋 歡迎加入！/ Chào mừng!', weight: 'bold', size: 'lg', align: 'center' },
      { type: 'separator', margin: 'md' },
      {
        type: 'box',
        layout: 'horizontal',
        margin: 'lg',
        spacing: 'sm',
        contents: [
          { type: 'button', style: 'primary', color: '#06C755', action: { type: 'postback', label: '🇹🇼 繁體中文', data: 'action=lang&value=zh-TW' } },
          { type: 'button', style: 'secondary', action: { type: 'postback', label: '🇻🇳 Tiếng Việt', data: 'action=lang&value=vi-VN' } }
        ]
      }
    ]
  }
};
return {
  json: {
    replyToken: d.replyToken,
    replyType: 'flex',
    text: '請選擇語言',
    altText: '請選擇語言',
    flexContents: flexContents
  }
};

const emp = $('查詢員工表').item.json;
const input = $('擷取訊息資訊').item.json;
const now = new Date();
const lastActive = emp.last_active ? new Date(isNaN(Number(emp.last_active)) ? emp.last_active : Number(emp.last_active)) : new Date(0);
const TIMEOUT_MS = 10 * 60 * 1000;
const isTimeout = (now - lastActive) > TIMEOUT_MS && emp.current_step && emp.current_step !== 'IDLE';
const pbData = input.postbackData || '';
const pbParams = {};
pbData.split('&').forEach(p => { const [k, v] = p.split('='); if (k && v) pbParams[k] = decodeURIComponent(v); });
const MSG = {'zh-TW': {timeout: '⏰ 操作逾時', cancel: '✅ 已取消', selectStore: '請選擇門市 👇', storeList: '請選擇門市 👇', photoIn: '📸 請拍攝上班照', photoOut: '📸 請拍攝下班照', photoId: '📸 請拍攝證件照', askPhoto: '📸 請拍攝證件照', wrongInput: '❓ 請依指示操作', regOk: '✅ 註冊成功！', inOk: '✅ 上班成功！', outOk: '✅ 下班成功！', help: '📋 指令：上班/下班/取消', noClockIn: '⚠️ 今日尚未打上班卡', askRevenue: '💰 請輸入當前業績:', revenueOk: '✅ 已記錄業績', welcome: '歡迎加入！', selectLang: '請選擇語言', helper: '✨ 您是今日小幫手 (免業績)', opener: '🎯 您是首位開攤', midshift: '🕒 中途上班，請先輸入業績'}, 'vi-VN': {timeout: '⏰ Hết giờ', cancel: '✅ Đã hủy', selectStore: 'Chọn cửa hàng 👇', storeList: 'Chọn cửa hàng 👇', photoIn: '📸 Chụp ảnh đi làm', photoOut: '📸 Chụp ảnh tan ca', photoId: '📸 Chụp ảnh ID', askPhoto: '📸 Vui lòng chụp ảnh ID', wrongInput: '❓ Làm theo hướng dẫn', regOk: '✅ Đăng ký xong!', inOk: '✅ Đi làm OK!', outOk: '✅ Tan ca OK!', help: '📋 Lệnh: Bắt đầu/Kết thúc/Hủy', noClockIn: '⚠️ Chưa chấm công', askRevenue: '💰 Nhập doanh số:', revenueOk: '✅ Đã ghi doanh số', welcome: 'Xin chào!', selectLang: 'Vui lòng chọn ngôn ngữ', helper: '✨ Bạn là trợ lý (Không cần KPI)', opener: '🎯 Bạn là người mở hàng', midshift: '🕒 Ca giữa, vui lòng nhập doanh số'}};
const lang = emp.Language || 'zh-TW';
const t = MSG[lang] || MSG['zh-TW'];
let tempData = {};
try { tempData = emp.temp_data ? JSON.parse(emp.temp_data) : {}; } catch(e) {}
return { json: { ...input, emp, lang, t, MSG_DICT: MSG, isTimeout, step: emp.current_step || 'IDLE', tempData, pbParams, combinedAction: pbParams.action || '', combinedValue: pbParams.value || pbParams.store || '' } };

const d = $input.item.json;
const store = d.combinedValue || d.pbParams.store || d.msgText;
const action = 'clockin';
const newTemp = JSON.stringify({ action, store });
return { json: { ...d, store, action, newTemp } };

const prev = $('解析店名(上班)').item.json;
const dailyRevRows = $input.all();
const store = prev.store;
// 台灣時區 UTC+8
const now = new Date();
const twOffset = 8 * 60 * 60 * 1000;
const twNow = new Date(now.getTime() + twOffset);
const todayStr = `${twNow.getUTCFullYear()}/${String(twNow.getUTCMonth()+1).padStart(2,'0')}/${String(twNow.getUTCDate()).padStart(2,'0')}`;
const todayRecords = dailyRevRows.filter(r => {
  const d = r.json['日期'] || '';
  return d.includes(todayStr) || d.startsWith(`${twNow.getUTCMonth()+1}/${twNow.getUTCDate()}`);
});
let clockInType = 'opener';
let openTime = null;
if (todayRecords.length > 0 && todayRecords[0].json['開攤時間']) {
  const openTimeStr = todayRecords[0].json['開攤時間'];
  const match = openTimeStr.match(/(\d{1,2}):(\d{2})/);
  if (match) {
    let hour = parseInt(match[1]);
    const min = parseInt(match[2]);
    if (openTimeStr.includes('下午') && hour < 12) hour += 12;
    const diffHr = (twNow.getUTCHours() * 60 + twNow.getUTCMinutes() - (hour * 60 + min)) / 60;
    clockInType = diffHr < 1 ? 'helper' : 'midshift';
  }
}
let tempObj = {};
try { tempObj = JSON.parse(prev.newTemp); } catch(e) { tempObj = { raw: prev.newTemp }; }
const newTemp = JSON.stringify({ ...tempObj, store, clockInType, clockInTime: twNow.toISOString() });
return { json: { ...prev, store, clockInType, hasOpenRecord: todayRecords.length > 0, newTemp } };

const d = $input.item.json;
const store = d.combinedValue || d.pbParams.store || d.msgText;
const action = 'clockout';
const newTemp = JSON.stringify({ action, store });
return { json: { ...d, store, action, newTemp } };

const prev = $('解析店名(下班)').item.json;
const emp = prev.emp;
let helper = false;
// 簡單判斷：若 current_step 曾記錄是 helper 或 tempData 裡有標記
if (prev.t.helper) {/*不做額外判斷，由路由決定*/} 
// 這裡假設若為helper，不需業績
// 實務上可到Google Sheet查今日上班若是helper則不需業績
return { json: { ...prev } };

const d = $input.item.json;
const revenue = parseInt(d.msgText.replace(/\D/g, '')) || 0;
const prevTemp = d.tempData || {};
const newTemp = JSON.stringify({ ...prevTemp, revenue });
return { json: { ...d, revenue, newTemp } };

const d = $('擷取訊息資訊').item.json;
const postbackData = d.postbackData || '';
let lang = 'zh-TW';

// 解析 Postback Data (例如: "action=lang&value=vi-VN")
if (postbackData.includes('value=')) {
  const match = postbackData.match(/value=([^&]+)/);
  if (match && match[1]) {
    lang = match[1];
  }
}

// 若解析失敗或非合法值，預設 zh-TW
if (lang !== 'vi-VN' && lang !== 'zh-TW') {
    lang = 'zh-TW';
}

return { json: { ...d, lang } };

const { DateTime } = require('luxon');
const d = $input.item.json;
const emp = d.emp || {};
const tempData = d.tempData || {};
const store = tempData.store || '';
const nickname = emp['暱稱'] || d.userId;
const step = emp.current_step;

// 判斷動作
let action = '';
if (step === 'WAIT_PHOTO_IN') action = '上班';
else if (step === 'WAIT_PHOTO_OUT') action = '下班';
else if (step === 'WAIT_PHOTO_REG') action = '註冊';

// 格式化時間 (台灣時區)
const twTime = DateTime.now().setZone('Asia/Taipei');
const dateStr = twTime.toFormat('yyyy/MM/dd');
const timeStr = twTime.toFormat('TT'); // e.g. 02:30:00 PM
// Manual am/pm format if needed or use standard
const ampm = twTime.hour >= 12 ? '下午' : '上午';
const hour12 = twTime.hour % 12 || 12;
const min = twTime.minute.toString().padStart(2, '0');
const sec = twTime.second.toString().padStart(2, '0');
const customTimeStr = `${ampm} ${hour12}:${min}:${sec}`;

// 組合檔名
let prefix = '';
if (store) prefix += `[${store}]`;
prefix += `[${nickname}${action}]`;

const fileName = `${prefix} ${dateStr} ${customTimeStr}.jpg`;

return { json: { ...d, fileName, dateStr, timeStr: customTimeStr } };

const drive = $input.item.json;
const driveLink = drive.webViewLink;
// 取得最原始的input資料以知道當前step
const rootItem = $('讀取狀態與翻譯').item.json;
const step = rootItem.step;

// 嘗試解析 temp_data 以取得 row_number (針對下班打卡)
let row_number = 0;
try {
  const temp = typeof rootItem.temp_data === 'string' ? JSON.parse(rootItem.temp_data) : rootItem.temp_data;
  if (temp && temp.row_number) {
    row_number = parseInt(temp.row_number);
  }
} catch (e) {}

// 從「生成檔名」節點取得日期時間資訊
const genFile = $('生成檔名').item.json;
const { dateStr, timeStr, fileName } = genFile;
return { json: { step, driveLink, ...rootItem, dateStr, timeStr, fileName, row_number } };

const stores = $('讀取分店清單').item.json || [];
// 假設分店清單有「店名」欄位
// 依需求可能有多個欄位，這裡只取店名
const items = [];
// 若是來自 google sheets 讀取多筆，stores 可能是陣列或單筆
// 在 n8n code node 中，$input.all() 取所有
const allStores = $('讀取分店清單').all().map(i => i.json['分店清單']).filter(n => n);

// 建立 Quick Reply Items
allStores.forEach(s => {
  items.push({
    type: 'action',
    action: {
      type: 'message',
      label: s,
      text: s
    }
  });
});

// 加上「取消」按鈕
items.push({
  type: 'action',
  action: {
    type: 'postback',
    label: '取消',
    data: 'action=cancel'
  }
});

const root = $('讀取狀態與翻譯').item.json;
const t = root.t;

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'quickReply',
    text: t.selectStore || '請選擇分店',
    quickReplyItems: items
  }
};

const root = $('讀取狀態與翻譯').item.json;
const flowData = $('準備結果資料').item.json;
const t = root.t;
const step = flowData.step;
const store = flowData.tempData?.store || '';
const nowStr = new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei', hour12: false });

let msg = '';
if (step === 'WAIT_PHOTO_REG') {
  msg = t.regOk || '註冊成功';
} else if (step === 'WAIT_PHOTO_IN') {
  msg = (t.inOk || '上班打卡成功') + '\n🏪 ' + store + '\n⏰ ' + nowStr;
} else if (step === 'WAIT_PHOTO_OUT') {
  msg = (t.outOk || '下班打卡成功') + '\n🏪 ' + store + '\n⏰ ' + nowStr;
} else {
  msg = '操作成功';
}

const flexContents = {
  type: 'bubble',
  body: {
    type: 'box',
    layout: 'vertical',
    contents: [
      { type: 'text', text: msg, weight: 'bold', size: 'lg', wrap: true, color: '#1DB446' }
    ]
  }
};

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'flex',
    text: msg,
    altText: msg,
    flexContents
  }
};

const root = $('讀取狀態與翻譯').item.json;
const t = root.t;
return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: t.cancel
  }
};

