const root = $('讀取狀態與翻譯').item.json;
const t = root.t;
return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: t.wrongInput
  }
};

const records = $input.all();
const emp = $('讀取狀態與翻譯').item.json.emp;
// 判斷是否已上班但未下班
// records 包含今日所有該員工紀錄
// 找一筆 "上班時間" 有值 但 "下班時間" 空的
const activeShift = records.find(r => r.json['上班時間'] && !r.json['下班時間']);
const clockInStatus = activeShift ? 'active' : 'none';
let row_number = 0;
let store = null;
if (activeShift) {
  // 優先使用 n8n 自動注入的 row_number，若無則嘗試從 json 屬性抓取
  row_number = activeShift.json.row_number || activeShift.row_number || 0;
  store = activeShift.json['店名'] || null;
}

return { json: { clockInStatus, row_number, store, emp, ...$('讀取狀態與翻譯').item.json } };

const root = $('讀取狀態與翻譯').item.json;
const t = root.t;
return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: t.askRevenue + ' ' + $('判斷上下班').item.json.store
  }
};
